146→                        let _result =
147→                            backend.set_index_text(&path, content, &env);
148→                        let entries = backend.status(&[]).unwrap_or_default();
149→                        entity
150→                            .update(cx, |repo: &mut Repository, cx| {
151→                                repo.statuses = entries;
152→                                cx.emit(RepositoryEvent::IndexChanged);
153→                                cx.notify();
154→                            })
155→                            .ok();
156→                    }
157→                    GitJob::Commit { message, options } => {
158→                        let was_amend = options.amend;
159→                        let _result =
160→                            backend.commit(&message, &options, &env);
161→                        let entries = backend.status(&[]).unwrap_or_default();
162→                        let branch = backend.current_branch();
163→                        entity
164→                            .update(cx, |repo: &mut Repository, cx| {
165→                                repo.statuses = entries;
166→                                repo.snapshot.branch = branch;
167→                                cx.emit(RepositoryEvent::CommitCompleted { was_amend });
