169→                            })
170→                            .ok();
171→                    }
172→                    GitJob::Push {
173→                        branch,
174→                        remote,
175→                        options,
176→                    } => {
177→                        let _result = backend.push(
178→                            &branch,
179→                            remote.as_deref(),
180→                            &options,
181→                            &env,
