183→                    }
184→                    GitJob::Pull { rebase } => {
185→                        let _result = backend.pull(rebase, &env);
186→                        let entries = backend.status(&[]).unwrap_or_default();
187→                        let branch = backend.current_branch();
188→                        entity
189→                            .update(cx, |repo: &mut Repository, cx| {
190→                                repo.statuses = entries;
191→                                repo.snapshot.branch = branch;
192→                                cx.emit(RepositoryEvent::BranchChanged);
