246→    /// Commit staged changes.
247→    pub fn commit(
248→        &mut self,
249→        message: String,
250→        options: CommitOptions,
251→        _cx: &mut Context<Self>,
252→    ) {
253→        let _ = self
254→            .job_sender
255→            .send(GitJob::Commit { message, options });
256→    }
257→
258→    /// Push to remote.
259→    pub fn push(
260→        &self,
261→        branch: String,
262→        remote: Option<String>,
263→        options: PushOptions,
264→    ) {
265→        let _ = self.job_sender.send(GitJob::Push {
266→            branch,
267→            remote,
268→            options,
269→        });
270→    }
271→
272→    /// Pull from remote.
273→    pub fn pull(&self, rebase: bool) {
274→        let _ = self.job_sender.send(GitJob::Pull { rebase });
275→    }
276→
277→    /// Fetch from remote.
278→    pub fn fetch(&self) {
279→        let _ = self.job_sender.send(GitJob::Fetch);
280→    }
281→
282→    /// Trigger a status refresh.
283→    pub fn refresh_status(&self) {
284→        let _ = self.job_sender.send(GitJob::RefreshStatus);
285→    }
286→
287→    /// Get the current snapshot for cheap UI reads.
288→    pub fn snapshot(&self) -> &RepositorySnapshot {
289→        &self.snapshot
290→    }
291→
292→    /// Get current status entries.
293→    pub fn statuses(&self) -> &[StatusEntry] {
294→        &self.statuses
295→    }
296→
297→    /// Get the effective staging state for a path, accounting for pending ops.
298→    pub fn effective_staging_state(&self, path: &RepoPath) -> StagingState {
299→        if let Some(pending) = self.pending_ops.get(path) {
300→            return match pending {
301→                PendingOp::Staging => StagingState::Staged,
302→                PendingOp::Unstaging => StagingState::Unstaged,
303→            };
304→        }
305→
306→        self.statuses
307→            .iter()
308→            .find(|s| &s.repo_path == path)
309→            .map(|s| s.staging_state())
310→            .unwrap_or(StagingState::Unstaged)
311→    }
312→
313→    /// Get the underlying git repository.
314→    pub fn git_repo(&self) -> &Arc<dyn GitRepository> {
315→        &self.git_repo
316→    }
317→}
