 58→    pub fn blend(&self, other: Rgba) -> Self {
 59→        if other.a >= 1.0 {
 60→            other
 61→        } else if other.a <= 0.0 {
 62→            *self
 63→        } else {
 64→            Rgba {
 65→                r: (self.r * (1.0 - other.a)) + (other.r * other.a),
 66→                g: (self.g * (1.0 - other.a)) + (other.g * other.a),
 67→                b: (self.b * (1.0 - other.a)) + (other.b * other.a),
