132→impl From<Hsla> for Rgba {
133→    fn from(color: Hsla) -> Self {
134→        let h = color.h;
135→        let s = color.s;
136→        let l = color.l;
137→
138→        let c = (1.0 - (2.0 * l - 1.0).abs()) * s;
139→        let x = c * (1.0 - ((h * 6.0) % 2.0 - 1.0).abs());
140→        let m = l - c / 2.0;
141→        let cm = c + m;
142→        let xm = x + m;
143→
144→        let (r, g, b) = match (h * 6.0).floor() as i32 {
145→            0 | 6 => (cm, xm, m),
146→            1 => (xm, cm, m),
147→            2 => (m, cm, xm),
148→            3 => (m, xm, cm),
149→            4 => (xm, m, cm),
150→            _ => (cm, m, xm),
151→        };
152→
153→        Rgba {
154→            r: r.clamp(0., 1.),
155→            g: g.clamp(0., 1.),
156→            b: b.clamp(0., 1.),
157→            a: color.a,
158→        }
159→    }
160→}
