507→    /// Returns a new HSLA color with the same hue, and lightness, but with no saturation.
508→    pub fn grayscale(&self) -> Self {
509→        Hsla {
510→            h: self.h,
511→            s: 0.,
512→            l: self.l,
513→            a: self.a,
514→        }
515→    }
