589→impl From<Rgba> for Hsla {
590→    fn from(color: Rgba) -> Self {
591→        let r = color.r;
592→        let g = color.g;
593→        let b = color.b;
594→
595→        let max = r.max(g.max(b));
596→        let min = r.min(g.min(b));
597→        let delta = max - min;
598→
599→        let l = (max + min) / 2.0;
600→        let s = if l == 0.0 || l == 1.0 {
601→            0.0
602→        } else if l < 0.5 {
603→            delta / (2.0 * l)
604→        } else {
605→            delta / (2.0 - 2.0 * l)
606→        };
607→
608→        let h = if delta == 0.0 {
609→            0.0
610→        } else if max == r {
611→            ((g - b) / delta).rem_euclid(6.0) / 6.0
612→        } else if max == g {
613→            ((b - r) / delta + 2.0) / 6.0
614→        } else {
615→            ((r - g) / delta + 4.0) / 6.0
616→        };
617→
618→        Hsla {
619→            h,
620→            s,
621→            l,
622→            a: color.a,
623→        }
624→    }
625→}
