 12→/// In-memory `GitRepository` implementation for testing.
 13→///
 14→/// Stores head, index, and working tree state in `HashMap`s and derives
 15→/// status by comparing them. No real git repo or filesystem needed.
 16→pub struct FakeGitRepository {
 17→    head: Mutex<HashMap<RepoPath, String>>,
 18→    index: Mutex<HashMap<RepoPath, String>>,
 19→    worktree: Mutex<HashMap<RepoPath, String>>,
 20→    current_branch: Mutex<Option<String>>,
 21→    branches: Mutex<Vec<Branch>>,
 22→    commits: Mutex<Vec<CommitSummary>>,
 23→    path: PathBuf,
 24→    work_directory: Option<PathBuf>,
 25→}
 26→
 27→impl FakeGitRepository {
 28→    pub fn new(path: PathBuf) -> Self {
 29→        let work_dir = Some(path.clone());
 30→        Self {
 31→            head: Mutex::new(HashMap::new()),
 32→            index: Mutex::new(HashMap::new()),
 33→            worktree: Mutex::new(HashMap::new()),
 34→            current_branch: Mutex::new(Some("main".to_string())),
 35→            branches: Mutex::new(vec![Branch {
 36→                name: "main".to_string(),
 37→                upstream: None,
 38→                is_head: true,
 39→                unix_timestamp: None,
 40→            }]),
 41→            commits: Mutex::new(Vec::new()),
 42→            path,
 43→            work_directory: work_dir,
 44→        }
 45→    }
 46→
 47→    pub fn set_head_content(&self, path: RepoPath, content: &str) {
 48→        self.head
 49→            .lock()
 50→            .unwrap()
 51→            .insert(path.clone(), content.to_string());
 52→        // Also set in index to match (committed files are in both HEAD and index)
 53→        self.index
 54→            .lock()
 55→            .unwrap()
 56→            .insert(path, content.to_string());
 57→    }
 58→
 59→    pub fn set_index_content(&self, path: RepoPath, content: &str) {
 60→        self.index
 61→            .lock()
 62→            .unwrap()
 63→            .insert(path, content.to_string());
 64→    }
 65→
 66→    pub fn set_worktree_content(&self, path: RepoPath, content: &str) {
 67→        self.worktree
 68→            .lock()
 69→            .unwrap()
 70→            .insert(path, content.to_string());
 71→    }
 72→
 73→    pub fn remove_worktree_content(&self, path: &RepoPath) {
 74→        self.worktree.lock().unwrap().remove(path);
 75→    }
 76→
 77→    pub fn set_branch(&self, name: &str) {
 78→        *self.current_branch.lock().unwrap() = Some(name.to_string());
 79→    }
 80→
 81→    pub fn add_commit(&self, summary: CommitSummary) {
 82→        self.commits.lock().unwrap().push(summary);
 83→    }
 84→
 85→    fn derive_status_for(
 86→        &self,
 87→        path: &RepoPath,
 88→        head: &HashMap<RepoPath, String>,
 89→        index: &HashMap<RepoPath, String>,
 90→        worktree: &HashMap<RepoPath, String>,
 91→    ) -> Option<GitFileStatus> {
 92→        let in_head = head.get(path);
 93→        let in_index = index.get(path);
 94→        let in_worktree = worktree.get(path);
 95→
 96→        // Derive index_status by comparing index vs head
 97→        let index_status = match (in_head, in_index) {
 98→            (None, None) => FileStatus::Unchanged,
 99→            (None, Some(_)) => FileStatus::Added,
100→            (Some(_), None) => FileStatus::Deleted,
101→            (Some(h), Some(i)) => {
102→                if h == i {
103→                    FileStatus::Unchanged
104→                } else {
105→                    FileStatus::Modified
106→                }
107→            }
108→        };
109→
110→        // Derive worktree_status by comparing worktree vs index
111→        let worktree_status = match (in_index, in_worktree) {
112→            (None, None) => return None, // not tracked, not in worktree
113→            (None, Some(_)) => {
114→                if in_head.is_none() {
115→                    FileStatus::Untracked
116→                } else {
117→                    // Deleted from index but present in worktree
118→                    FileStatus::Modified
119→                }
120→            }
121→            (Some(_), None) => FileStatus::Deleted,
122→            (Some(i), Some(w)) => {
123→                if i == w {
124→                    FileStatus::Unchanged
125→                } else {
126→                    FileStatus::Modified
127→                }
128→            }
129→        };
130→
131→        // If both unchanged and file exists, it's a clean file — no status entry
132→        if index_status == FileStatus::Unchanged && worktree_status == FileStatus::Unchanged {
133→            return None;
134→        }
135→
136→        Some(GitFileStatus {
137→            index_status,
138→            worktree_status,
139→            conflict: false,
140→        })
141→    }
142→}
