258→        _options: &CommitOptions,
259→        _env: &HashMap<String, String>,
260→    ) -> GitResult<()> {
261→        let index = self.index.lock().unwrap();
262→        let mut head = self.head.lock().unwrap();
263→
264→        // Copy index state to head
