405→    fn show(&self, oid: &str) -> GitResult<CommitDetails> {
406→        let commits = self.commits.lock().unwrap();
407→        let summary = commits
408→            .iter()
409→            .find(|c| c.sha == oid)
410→            .cloned()
411→            .ok_or_else(|| {
