        repo.checkout("feature", &HashMap::new()).unwrap();
        assert_eq!(
            repo.current_branch().unwrap().name,
            "feature"
        );

        repo.delete_branch("feature").unwrap();
        let branches = repo.branches().unwrap();
        assert_eq!(branches.len(), 1);
    }
