  1→use gpui::{
  2→    div, AppContext, Context, Entity, FocusHandle, IntoElement, ParentElement, Render,
  3→    StatefulInteractiveElement, Styled, Subscription, Window,
  4→};
  5→
  6→use crate::actions::{
  7→    Commit, SelectNext, SelectPrev, StageAll, ToggleStaging, UnstageAll,
  8→};
  9→use crate::git::repo_entity::Repository;
 10→use crate::git::store::{GitStore, GitStoreEvent};
 11→use crate::git::types::{CommitOptions, FileStatus, RepoPath, StagingState, StatusEntry};
 12→use crate::theme::Theme;
 13→
 14→// ---------------------------------------------------------------------------
 15→// Entry — a file in the staged or unstaged section
 16→// ---------------------------------------------------------------------------
 17→
 18→#[derive(Clone, Debug)]
 19→struct PanelEntry {
 20→    status_entry: StatusEntry,
 21→    staged: bool,
 22→}
 23→
 24→// ---------------------------------------------------------------------------
 25→// GitPanel
 26→// ---------------------------------------------------------------------------
 27→
 28→pub struct GitPanel {
 29→    git_store: Entity<GitStore>,
 30→    entries: Vec<PanelEntry>,
 31→    selected_index: Option<usize>,
 32→    commit_message: String,
 33→    focus_handle: FocusHandle,
 34→    _subscriptions: Vec<Subscription>,
 35→}
 36→
 37→impl GitPanel {
 38→    pub fn new(
 39→        git_store: Entity<GitStore>,
 40→        cx: &mut Context<Self>,
 41→    ) -> Self {
 42→        let focus_handle = cx.focus_handle();
 43→
 44→        let sub = cx.subscribe(&git_store, |this: &mut Self, _store, event, cx| {
 45→            match event {
 46→                GitStoreEvent::StatusesChanged(_)
 47→                | GitStoreEvent::ActiveRepositoryChanged
 48→                | GitStoreEvent::BranchChanged => {
 49→                    this.rebuild_entries(cx);
 50→                    cx.notify();
 51→                }
 52→                GitStoreEvent::CommitCompleted { .. } => {
 53→                    this.commit_message.clear();
 54→                    this.rebuild_entries(cx);
 55→                    cx.notify();
 56→                }
 57→            }
 58→        });
 59→
 60→        let mut panel = Self {
 61→            git_store,
 62→            entries: Vec::new(),
 63→            selected_index: None,
 64→            commit_message: String::new(),
 65→            focus_handle,
 66→            _subscriptions: vec![sub],
 67→        };
 68→
 69→        panel.rebuild_entries(cx);
 70→        panel
 71→    }
 72→
 73→    fn rebuild_entries(&mut self, cx: &mut Context<Self>) {
 74→        self.entries.clear();
 75→
 76→        let store = self.git_store.read(cx);
 77→        let Some(repo_entity) = store.active_repository() else {
 78→            return;
 79→        };
 80→
 81→        let repo = repo_entity.read(cx);
 82→
 83→        for entry in repo.statuses() {
 84→            let effective = repo.effective_staging_state(&entry.repo_path);
 85→            match effective {
 86→                StagingState::Staged => {
 87→                    self.entries.push(PanelEntry {
 88→                        status_entry: entry.clone(),
 89→                        staged: true,
 90→                    });
 91→                }
 92→                StagingState::Unstaged => {
 93→                    self.entries.push(PanelEntry {
 94→                        status_entry: entry.clone(),
 95→                        staged: false,
 96→                    });
 97→                }
 98→                StagingState::PartiallyStaged => {
 99→                    self.entries.push(PanelEntry {
100→                        status_entry: entry.clone(),
101→                        staged: true,
102→                    });
103→                    self.entries.push(PanelEntry {
104→                        status_entry: entry.clone(),
105→                        staged: false,
106→                    });
107→                }
108→            }
109→        }
110→
111→        // Sort: staged first, then unstaged; within each group, by path
112→        self.entries.sort_by(|a, b| {
113→            b.staged
114→                .cmp(&a.staged)
115→                .then_with(|| a.status_entry.repo_path.cmp(&b.status_entry.repo_path))
116→        });
117→
118→        // Clamp selection
119→        if let Some(idx) = self.selected_index {
120→            if idx >= self.entries.len() {
121→                self.selected_index = if self.entries.is_empty() {
122→                    None
123→                } else {
124→                    Some(self.entries.len() - 1)
125→                };
126→            }
127→        }
128→    }
129→
130→    fn staged_entries(&self) -> Vec<&PanelEntry> {
131→        self.entries.iter().filter(|e| e.staged).collect()
132→    }
133→
134→    fn unstaged_entries(&self) -> Vec<&PanelEntry> {
135→        self.entries.iter().filter(|e| !e.staged).collect()
136→    }
137→
138→    fn toggle_staging_for(
139→        &mut self,
140→        path: RepoPath,
141→        currently_staged: bool,
142→        cx: &mut Context<Self>,
143→    ) {
144→        let store = self.git_store.read(cx);
145→        let Some(repo_entity) = store.active_repository().cloned() else {
146→            return;
147→        };
148→
149→        if currently_staged {
150→            repo_entity.update(cx, |repo, cx| {
151→                repo.unstage(vec![path], cx);
152→            });
153→        } else {
154→            repo_entity.update(cx, |repo, cx| {
155→                repo.stage(vec![path], cx);
156→            });
157→        }
158→    }
159→
160→    fn stage_all(&mut self, cx: &mut Context<Self>) {
161→        let paths: Vec<RepoPath> = self
162→            .unstaged_entries()
163→            .iter()
164→            .map(|e| e.status_entry.repo_path.clone())
165→            .collect();
166→
167→        if paths.is_empty() {
168→            return;
169→        }
170→
171→        let store = self.git_store.read(cx);
172→        let Some(repo_entity) = store.active_repository().cloned() else {
173→            return;
174→        };
175→
176→        repo_entity.update(cx, |repo, cx| {
177→            repo.stage(paths, cx);
178→        });
179→    }
180→
181→    fn unstage_all(&mut self, cx: &mut Context<Self>) {
182→        let paths: Vec<RepoPath> = self
183→            .staged_entries()
184→            .iter()
185→            .map(|e| e.status_entry.repo_path.clone())
186→            .collect();
187→
188→        if paths.is_empty() {
189→            return;
190→        }
191→
192→        let store = self.git_store.read(cx);
193→        let Some(repo_entity) = store.active_repository().cloned() else {
194→            return;
195→        };
196→
197→        repo_entity.update(cx, |repo, cx| {
198→            repo.unstage(paths, cx);
199→        });
200→    }
201→
202→    fn toggle_selected(&mut self, cx: &mut Context<Self>) {
203→        let Some(idx) = self.selected_index else {
204→            return;
205→        };
206→        let Some(entry) = self.entries.get(idx) else {
207→            return;
208→        };
209→        let path = entry.status_entry.repo_path.clone();
210→        let staged = entry.staged;
211→        self.toggle_staging_for(path, staged, cx);
212→    }
213→
214→    fn do_commit(&mut self, cx: &mut Context<Self>) {
215→        let message = self.commit_message.trim().to_string();
216→        if message.is_empty() {
217→            return;
218→        }
219→
220→        let store = self.git_store.read(cx);
221→        let Some(repo_entity) = store.active_repository().cloned() else {
222→            return;
223→        };
224→
225→        repo_entity.update(cx, |repo, cx| {
226→            repo.commit(message, CommitOptions::default(), cx);
227→        });
228→    }
229→
230→    fn select_next(&mut self, cx: &mut Context<Self>) {
231→        if self.entries.is_empty() {
232→            return;
233→        }
234→        self.selected_index = Some(match self.selected_index {
235→            None => 0,
236→            Some(idx) => (idx + 1).min(self.entries.len() - 1),
237→        });
238→        cx.notify();
239→    }
240→
241→    fn select_prev(&mut self, cx: &mut Context<Self>) {
242→        if self.entries.is_empty() {
243→            return;
244→        }
245→        self.selected_index = Some(match self.selected_index {
246→            None => 0,
247→            Some(idx) => idx.saturating_sub(1),
248→        });
249→        cx.notify();
250→    }
251→
252→    fn handle_key_down(
253→        &mut self,
254→        event: &gpui::KeyDownEvent,
255→        _window: &mut Window,
256→        cx: &mut Context<Self>,
257→    ) {
258→        let key_char = event.keystroke.key_char.as_deref();
259→        match key_char {
260→            Some(ch) if !event.keystroke.modifiers.command
261→                && !event.keystroke.modifiers.control =>
262→            {
263→                self.commit_message.push_str(ch);
264→                cx.notify();
265→            }
266→            _ => {
267→                // Handle special keys by key name
268→                match event.keystroke.key.as_str() {
269→                    "backspace" if !event.keystroke.modifiers.command => {
270→                        self.commit_message.pop();
271→                        cx.notify();
272→                    }
273→                    _ => {}
274→                }
275→            }
276→        }
277→    }
278→}
