281→    fn render(&mut self, _window: &mut Window, cx: &mut Context<Self>) -> impl IntoElement {
282→        let theme = cx.global::<Theme>();
283→        let focus_handle = self.focus_handle.clone();
284→
285→        // Read toolbar data
286→        let store = self.git_store.read(cx);
287→        let active_repo = store.active_repository();
288→
289→        let (branch_name, ahead, behind, total_files) = if let Some(repo_entity) = active_repo {
290→            let repo = repo_entity.read(cx);
291→            let snapshot = repo.snapshot();
292→            let name = snapshot
