595→
596→fn status_indicator(entry: &StatusEntry, staged: bool) -> &'static str {
597→    if staged {
598→        match entry.status.index_status {
599→            FileStatus::Added => "A",
600→            FileStatus::Modified => "M",
601→            FileStatus::Deleted => "D",
602→            FileStatus::Untracked => "?",
603→            FileStatus::Unchanged => " ",
604→        }
605→    } else {
606→        match entry.status.worktree_status {
607→            FileStatus::Added => "A",
608→            FileStatus::Modified => "M",
609→            FileStatus::Deleted => "D",
610→            FileStatus::Untracked => "?",
611→            FileStatus::Unchanged => " ",
612→        }
613→    }
614→}
615→
616→fn status_color(entry: &StatusEntry, staged: bool, theme: &Theme) -> gpui::Hsla {
617→    let file_status = if staged {
618→        entry.status.index_status
619→    } else {
620→        entry.status.worktree_status
621→    };
622→
623→    match file_status {
624→        FileStatus::Added | FileStatus::Untracked => theme.added,
625→        FileStatus::Modified => theme.modified,
626→        FileStatus::Deleted => theme.deleted,
627→        FileStatus::Unchanged => theme.text_muted,
628→    }
629→}
